import {{ Injectable }} from '@nestjs/common';
import {{ ConfigService }} from './models/config.model';
import {{ ConfigServiceRepository }} from './repositories/config.repository';

@Injectable()
export class ConfigServiceService {{
  constructor(
    private readonly repository: ConfigServiceRepository,
  ) {{}}

  async findAll(): Promise<ConfigService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<ConfigService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<ConfigService>): Promise<ConfigService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<ConfigService>): Promise<ConfigService> {{
    return this.repository.update(id, data);
  }}
}}
